import React, { useState } from "react";
import "../styles/GeneralChat.css";

const GeneralChat = () => {
  // 🔹 START EMPTY (no greeting on load)
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");

  const therapistReply = (userText, previousMessages) => {
    const text = userText.toLowerCase().trim();

    const lastBotMessage =
      previousMessages
        .slice()
        .reverse()
        .find((msg) => msg.sender === "bot")?.text.toLowerCase() || "";

    /* ------------------- STEP 0: GREETING ONLY ------------------- */
    if (text === "hello" || text === "hi" || text === "hey") {
      return "Hello. I’m glad you reached out today. How are you feeling right now?";
    }

    /* ------------------- STEP 1: Acknowledge FEELINGS ------------------- */
    if (
      text.includes("stress") ||
      text.includes("stressed") ||
      text.includes("pressure") ||
      text.includes("overwhelmed")
    ) {
      return "Thank you for sharing that. When you say you’re feeling stressed, can you tell me a bit more about what’s been contributing to those feelings?";
    }

    /* ------------------- STEP 2: SOURCE OF STRESS ------------------- */
    if (
      text.includes("study") ||
      text.includes("exam") ||
      text.includes("college")
    ) {
      return "That sounds like a lot to manage. What part of your studies feels most overwhelming right now?";
    }

    if (text.includes("work") || text.includes("job")) {
      return "Work pressure can be exhausting. What aspect of work has been weighing on you the most?";
    }

    if (text.includes("family")) {
      return "Family pressure can feel very heavy. Would you like to share what’s been happening at home?";
    }

    if (text.includes("future") || text.includes("career")) {
      return "Uncertainty about the future can be stressful. What worries you most when you think about it?";
    }

    /* ------------------- STEP 3: COPING ------------------- */
    if (
      text.includes("keep to myself") ||
      text.includes("alone") ||
      text.includes("silent")
    ) {
      return "Keeping everything inside can be exhausting. I appreciate your honesty. We can explore this together at a pace that feels comfortable for you.";
    }

    /* ------------------- STEP 4: IMPACT ------------------- */
    if (
      text.includes("sleep") ||
      text.includes("focus") ||
      text.includes("tired") ||
      text.includes("headache")
    ) {
      return "It sounds like this stress is affecting your daily life. How long have you been feeling this way?";
    }

    /* ------------------- FALLBACK ------------------- */
    if (text.length > 5) {
      return "I’m listening. Please tell me a little more about how you’ve been feeling.";
    }

    return "Take your time. You can share whenever you’re ready.";
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };
    const botReply = therapistReply(input, messages);

    // ⚠️ If user didn’t say hello first, don’t force greeting
    if (!botReply) return;

    const botMessage = { sender: "bot", text: botReply };

    setMessages([...messages, userMessage, botMessage]);
    setInput("");
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter") {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2 className="chat-title">💬 Professional Therapy Chat</h2>
        <p className="chat-subtitle">A safe space to talk</p>
      </div>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`message-group ${
              msg.sender === "user" ? "user-group" : "therapist-group"
            }`}
          >
            <div className="message-label">
              {msg.sender === "user" ? "You" : "Therapist"}
            </div>
            <div className={`message ${msg.sender}`}>
              {msg.text}
            </div>
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Type here…"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={handleKeyPress}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
